__declspec(dllexport) void run(void){
    u8 *add = (u8*)pop(256);
    u8 *id = cvm_payload();
    u32 id_len = cvm_payload_size();
    if (!id_len) { cont(); return; }
    u32 n = 0;
    u8 *s = cvm_var_get(id, id_len, &n);
    if (s && n) {
        u32 a = 0; while (a < n && s[a]) a++;
        u32 z = 0; while (z < 256 && add[z]) z++;
